compliant:
#include <stdexcept>
#include <string>

void goodFunction(const char* str) {
    // Compliant: input validation instead of errno
    if (str == nullptr || *str == '\0') {
        throw std::invalid_argument("Invalid input");
    }

    // Compliant: using return value checking
    char* endptr;
    long result = strtol(str, &endptr, 10);
    if (*endptr != '\0') {
        throw std::invalid_argument("Not a valid number");
    }
}

void properFileHandling() {
    // Compliant: direct return value checking
    FILE* file = fopen("test.txt", "r");
    if (file == nullptr) {
        throw std::runtime_error("Failed to open file");
    }
    fclose(file);
}
